DROP TABLE IF EXISTS `rentcast_cache`;
CREATE TABLE `rentcast_cache` (
  `cache_key` varchar(255) NOT NULL,
  `fetched_at` bigint NOT NULL,
  PRIMARY KEY (`cache_key`)
);

