DROP TABLE IF EXISTS `rentcast_listings`;
CREATE TABLE `rentcast_listings` (
  `id` varchar(255) NOT NULL,
  `cache_key` varchar(255) NOT NULL,
  `project_name` text NOT NULL,
  `borough` varchar(100) NOT NULL,
  `postcode` varchar(20) NOT NULL,
  `latitude` double NOT NULL,
  `longitude` double NOT NULL,
  `total_units` int NOT NULL DEFAULT '1',
  `rental_units` int NOT NULL DEFAULT '1',
  `building_status` varchar(50) NOT NULL,
  `completion_date` varchar(50) DEFAULT NULL,
  `price_min` decimal(12,2) NOT NULL DEFAULT '0.00',
  `price_max` decimal(12,2) NOT NULL DEFAULT '0.00',
  `bedrooms` int NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `fk_cache_key` (`cache_key`),
  KEY `idx_rentcast_listings_borough` (`borough`),
  KEY `idx_rentcast_listings_postcode` (`postcode`),
  CONSTRAINT `fk_cache_key` FOREIGN KEY (`cache_key`) REFERENCES `rentcast_cache` (`cache_key`) ON DELETE CASCADE
);

